def _select_Generic_superclass_parameters(subclass, superclass_origin):
    """Helper for _issubclass_Generic.
    """
    subclass = _find_base_with_origin(subclass, superclass_origin)
    if subclass is None:
        return None
    if subclass.__origin__ is superclass_origin:
        return subclass.__args__
    prms = _find_Generic_super_origin(subclass, superclass_origin)
    res = []
    for prm in prms:
        sub_search = subclass
        while not sub_search is None:
            try:
                res.append(sub_search.__args__[sub_search.__origin__.__parameters__.index(prm)])
                break
            except ValueError:
                # We search the closest base that actually contains the parameter
                sub_search = _find_base_with_origin(
                        sub_search.__origin__, superclass_origin)
        else:
            return None
    return res

def degree(self, kind='out', weighted=True):
    '''Returns an array of vertex degrees.
    kind : either 'in' or 'out', useful for directed graphs
    weighted : controls whether to count edges or sum their weights
    '''
    if kind == 'out':
      axis = 1
      adj = self.matrix('dense', 'csc')
    else:
      axis = 0
      adj = self.matrix('dense', 'csr')

    if not weighted and self.is_weighted():
      # With recent numpy and a dense matrix, could do:
      # d = np.count_nonzero(adj, axis=axis)
      d = (adj!=0).sum(axis=axis)
    else:
      d = adj.sum(axis=axis)
    return np.asarray(d).ravel()

