def tuplify(*args):
    """
    Convert args to a tuple, unless there's one arg and it's a
    function, then acts a decorator.
    """
    if (len(args) == 1) and callable(args[0]):
        func = args[0]

        @wraps(func)
        def _inner(*args, **kwargs):
            return tuple(func(*args, **kwargs))
        return _inner
    else:
        return tuple(args)

