    '''
    Formats packages according to parameters for list_pkgs.
    '''
    ret = copy.deepcopy(packages)
    if attr:
        requested_attr = {'epoch', 'version', 'release', 'arch', 'install_date', 'install_date_time_t'}

        if attr != 'all':
            requested_attr &= set(attr + ['version'])

        for name in ret:
            versions = []
            for all_attr in ret[name]:
                filtered_attr = {}
                for key in requested_attr:
                    if all_attr[key]:
                        filtered_attr[key] = all_attr[key]
                versions.append(filtered_attr)
            ret[name] = versions
        return ret

    for name in ret:
        ret[name] = [format_version(d['epoch'], d['version'], d['release'])
                     for d in ret[name]]
    if not versions_as_list:
        stringify(ret)
    return ret

def modelresource_factory(model, resource_class=ModelResource):
    """
    Factory for creating ``ModelResource`` class for given Django model.
    """
    attrs = {'model': model}
    Meta = type(str('Meta'), (object,), attrs)

    class_name = model.__name__ + str('Resource')

    class_attrs = {
        'Meta': Meta,
    }

    metaclass = ModelDeclarativeMetaclass
    return metaclass(class_name, (resource_class,), class_attrs)

def file_list_hosts( blockchain_id, wallet_keys=None, config_path=CONFIG_PATH ):
    """
    Given a blockchain ID, find out the hosts the blockchain ID owner has registered keys for.
    Return {'status': True, 'hosts': hostnames} on success
    Return {'error': ...} on failure
    """
    config_dir = os.path.dirname(config_path)
    try:
        ret = blockstack_gpg.gpg_list_app_keys( blockchain_id, APP_NAME, wallet_keys=wallet_keys, config_dir=config_dir )
    except Exception, e:
        ret = {'error': traceback.format_exc(e)}

    if 'error' in ret:
        log.error("Failed to list app keys: %s" % ret['error'])
        return {'error': 'Failed to list app keys'}

    hosts = []
    for key_info in ret:
        hostname = key_info['keyName']
        hosts.append(hostname)

    return {'status': True, 'hosts': hosts}

